Set-Location "d:\Projects\Gemini Live Hackathon\aura-live\coding agent"

$repo = "d:\Projects\Gemini Live Hackathon\aura-live\coding agent"
$vaultWiki = "d:\Projects\Gemini Live Hackathon\aura-live\aura brain vault\cc vault\claude code architecture brain\wiki"
$catalogDir = Join-Path $vaultWiki "catalog"

New-Item -ItemType Directory -Force -Path $catalogDir | Out-Null

$files = & rg --files -g "!node_modules/**" -g "!dist/**" -g "!*.map"

function Get-PurposeHint {
    param([string[]]$Lines, [string]$Fallback)

    $limit = [Math]::Min(40, $Lines.Count)
    for ($i = 0; $i -lt $limit; $i++) {
        $t = $Lines[$i].Trim()
        if ([string]::IsNullOrWhiteSpace($t)) {
            continue
        }

        if ($t.StartsWith("//") -and -not $t.StartsWith("///")) {
            $h = $t.TrimStart('/').Trim()
            if ($h.Length -gt 0 -and -not $h.StartsWith("eslint") -and -not $h.StartsWith("biome")) {
                return $h
            }
        }

        if ($t.StartsWith("# ")) {
            return $t.Substring(2).Trim()
        }

        if ($t.StartsWith("/*")) {
            $h = $t.TrimStart('/','*').TrimEnd('*','/').Trim()
            if ($h.Length -gt 0) {
                return $h
            }
        }

        if ($t.StartsWith("<!--") -and $t.Contains("Generated by Copilot")) {
            continue
        }
    }

    return $Fallback
}

function Get-SymbolHint {
    param([string]$Content, [string]$Ext)

    if ($Ext -notin @('.ts', '.tsx', '.js', '.jsx', '.mjs', '.cjs')) {
        return '-'
    }

    $names = New-Object System.Collections.Generic.List[string]
    $regexes = @(
        'export\s+(?:async\s+)?(?:function|const|class|type|interface|enum)\s+([A-Za-z0-9_]+)',
        'export\s+default\s+(?:class|function)?\s*([A-Za-z0-9_]+)',
        'function\s+([A-Za-z0-9_]+)\s*\('
    )

    foreach ($rx in $regexes) {
        $matches = [regex]::Matches($Content, $rx)
        foreach ($m in $matches) {
            if ($m.Groups.Count -gt 1) {
                $n = $m.Groups[1].Value
                if (-not [string]::IsNullOrWhiteSpace($n) -and -not $names.Contains($n)) {
                    $names.Add($n)
                    if ($names.Count -ge 5) {
                        break
                    }
                }
            }
        }

        if ($names.Count -ge 5) {
            break
        }
    }

    if ($names.Count -eq 0) {
        return '-'
    }

    return ($names -join ', ')
}

$records = foreach ($rel in $files) {
    $normalizedRel = $rel -replace '\\', '/'
    $segments = $normalizedRel -split '/'
    $top = if ($segments.Length -gt 1) { $segments[0] } else { '__root__' }

    $full = Join-Path $repo $rel
    $item = Get-Item -LiteralPath $full -ErrorAction SilentlyContinue
    $bytes = if ($item) { [int64]$item.Length } else { 0 }
    $ext = [System.IO.Path]::GetExtension($full).ToLowerInvariant()

    $status = 'text'
    $lineCount = 0
    $purpose = ''
    $symbols = '-'

    try {
        $content = Get-Content -LiteralPath $full -Raw -ErrorAction Stop
        $lines = $content -split "`r?`n"
        $lineCount = $lines.Count

        $baseFallback = if ($ext -eq '.md') {
            'Markdown documentation file'
        } elseif ($ext -eq '.ts' -or $ext -eq '.tsx') {
            'TypeScript module'
        } elseif ($ext -eq '.js' -or $ext -eq '.jsx') {
            'JavaScript module'
        } elseif ($ext -eq '.json') {
            'JSON configuration or data file'
        } else {
            'Source/support file'
        }

        $purpose = Get-PurposeHint -Lines $lines -Fallback $baseFallback
        $symbols = Get-SymbolHint -Content $content -Ext $ext
    } catch {
        $status = 'binary-or-unreadable'
        $lineCount = 0
        $purpose = 'Binary or unreadable file content'
        $symbols = '-'
    }

    [PSCustomObject]@{
        Top = $top
        Rel = $normalizedRel
        Lines = $lineCount
        Bytes = $bytes
        Symbols = $symbols
        Purpose = ($purpose -replace '\|', '\\|')
        Status = $status
    }
}

$groups = $records | Group-Object Top | Sort-Object Count -Descending

$index = New-Object System.Text.StringBuilder
$null = $index.AppendLine('<!-- Generated by Copilot -->')
$null = $index.AppendLine('# File-By-File Catalog Index')
$null = $index.AppendLine('')
$null = $index.AppendLine('This catalog is generated from all first-party files under `coding agent/` (excluding `node_modules`, `dist`, and `*.map`).')
$null = $index.AppendLine('')
$null = $index.AppendLine('## Coverage')
$null = $index.AppendLine('')
$null = $index.AppendLine("- Total files scanned: $($records.Count)")
$null = $index.AppendLine("- Generated on: $(Get-Date -Format 'yyyy-MM-dd HH:mm:ss')")
$null = $index.AppendLine('')
$null = $index.AppendLine('## Directory Catalogs')
$null = $index.AppendLine('')

foreach ($g in $groups) {
    $page = if ($g.Name -eq '__root__') { 'root-files.md' } else { "$($g.Name).md" }
    $title = if ($g.Name -eq '__root__') { 'root-files' } else { $g.Name }

    $sb = New-Object System.Text.StringBuilder
    $null = $sb.AppendLine('<!-- Generated by Copilot -->')
    $null = $sb.AppendLine("# Catalog: $title")
    $null = $sb.AppendLine('')
    $null = $sb.AppendLine("- Files: $($g.Count)")
    $null = $sb.AppendLine('')
    $null = $sb.AppendLine('| File | Lines | Bytes | Key Symbols | Purpose Hint | Status |')
    $null = $sb.AppendLine('|---|---:|---:|---|---|---|')

    $entries = $g.Group | Sort-Object Rel
    foreach ($r in $entries) {
        $sym = if ([string]::IsNullOrWhiteSpace($r.Symbols)) { '-' } else { $r.Symbols }
        $purposeOut = if ([string]::IsNullOrWhiteSpace($r.Purpose)) { '-' } else { $r.Purpose }
        $null = $sb.AppendLine("| $($r.Rel) | $($r.Lines) | $($r.Bytes) | $sym | $purposeOut | $($r.Status) |")
    }

    Set-Content -LiteralPath (Join-Path $catalogDir $page) -Value $sb.ToString() -Encoding UTF8
    $null = $index.AppendLine("- [$title](./$page) - $($g.Count) files")
}

Set-Content -LiteralPath (Join-Path $catalogDir 'index.md') -Value $index.ToString() -Encoding UTF8

Write-Output "Generated catalog pages: $($groups.Count + 1); files processed: $($records.Count)"
